     */
    data class SendMessage(
        val `text`: kotlin.String) : AppAction() {
        companion object
    }
    
    /**
     * Stop the active generation (per D-06, LLMC-07)
     */
    object StopGeneration : AppAction()
    
    
    /**
     * Set the active backend by ID (per D-09)
     */
    data class SetActiveBackend(
        val `backendId`: kotlin.String) : AppAction() {
        companion object
    }
    
    /**
     * Create a new conversation and navigate to the Chat screen (per D-12)
     */
    object NewConversation : AppAction()
    
    
    /**
     * Load a conversation's messages into AppState.messages (per D-05)
     */
    data class LoadConversation(
        val `conversationId`: kotlin.String) : AppAction() {
        companion object
    }
    
    /**
     * Rename a conversation title (per D-13)
     */
    data class RenameConversation(
