     */
    data class DeleteConversation(
        val `id`: kotlin.String) : AppAction() {
        companion object
    }
    
    /**
     * Retry: delete last assistant message and re-send the last user message (per D-07)
     */
    object RetryLastMessage : AppAction()
    
    
    /**
     * Edit a prior message: truncate history after it and re-submit (per D-08)
     */
    data class EditMessage(
        val `messageId`: kotlin.String, 
        val `newText`: kotlin.String) : AppAction() {
        companion object
    }
    
    /**
