/**
 * Error taxonomy for attestation operations -- crosses UniFFI boundary.
 * Mirrors LlmError pattern: thiserror for Display, uniffi::Error for FFI.
 */
sealed class AttestationException: kotlin.Exception() {
    
    class CollateralFetch(
        
        val `reason`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class QuoteVerification(
        
        val `reason`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class NonceMismatch(
        
        val `expected`: kotlin.String, 
        
        val `actual`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "expected=${ `expected` }, actual=${ `actual` }"
    }
    
    class JwtVerification(
        
        val `reason`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class CacheFailed(
        
        val `reason`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class Unsupported(
        ) : AttestationException() {
        override val message
            get() = ""
    }
    
    class NetworkException(
        
        val `reason`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class CacheLockPoisoned(
        ) : AttestationException() {
        override val message
            get() = ""
    }
    
    class UnsupportedTeeType(
        
        val `teeType`: kotlin.String
        ) : AttestationException() {
        override val message
            get() = "teeType=${ `teeType` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<AttestationException> {
        override fun lift(error_buf: RustBuffer.ByValue): AttestationException = FfiConverterTypeAttestationError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeAttestationError : FfiConverterRustBuffer<AttestationException> {
    override fun read(buf: ByteBuffer): AttestationException {
        

        return when(buf.getInt()) {
            1 -> AttestationException.CollateralFetch(
                FfiConverterString.read(buf),
                )
            2 -> AttestationException.QuoteVerification(
                FfiConverterString.read(buf),
                )
            3 -> AttestationException.NonceMismatch(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            4 -> AttestationException.JwtVerification(
                FfiConverterString.read(buf),
                )
            5 -> AttestationException.CacheFailed(
                FfiConverterString.read(buf),
                )
            6 -> AttestationException.Unsupported()
            7 -> AttestationException.NetworkException(
                FfiConverterString.read(buf),
                )
            8 -> AttestationException.CacheLockPoisoned()
            9 -> AttestationException.UnsupportedTeeType(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: AttestationException): ULong {
        return when(value) {
            is AttestationException.CollateralFetch -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is AttestationException.QuoteVerification -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is AttestationException.NonceMismatch -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`expected`)
                + FfiConverterString.allocationSize(value.`actual`)
            )
            is AttestationException.JwtVerification -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is AttestationException.CacheFailed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is AttestationException.Unsupported -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is AttestationException.NetworkException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is AttestationException.CacheLockPoisoned -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is AttestationException.UnsupportedTeeType -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`teeType`)
            )
        }
    }

    override fun write(value: AttestationException, buf: ByteBuffer) {
        when(value) {
            is AttestationException.CollateralFetch -> {
                buf.putInt(1)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationException.QuoteVerification -> {
                buf.putInt(2)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationException.NonceMismatch -> {
                buf.putInt(3)
                FfiConverterString.write(value.`expected`, buf)
                FfiConverterString.write(value.`actual`, buf)
                Unit
            }
            is AttestationException.JwtVerification -> {
                buf.putInt(4)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationException.CacheFailed -> {
                buf.putInt(5)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationException.Unsupported -> {
                buf.putInt(6)
                Unit
            }
            is AttestationException.NetworkException -> {
                buf.putInt(7)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationException.CacheLockPoisoned -> {
                buf.putInt(8)
                Unit
            }
            is AttestationException.UnsupportedTeeType -> {
                buf.putInt(9)
                FfiConverterString.write(value.`teeType`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * Attestation verification status for a backend.
 *
 * Crosses the UniFFI boundary per D-10. Carried in AppState as
 * Vec<(backend_id, AttestationStatus)> per D-11.
 */
sealed class AttestationStatus {
    
    /**
     * Cryptographic verification passed (TDX quote, SNP report, or NRAS JWT verified).
     */
    object Verified : AttestationStatus()
    
    
    /**
     * Not yet checked or no attestation endpoint available for this backend.
     */
    object Unverified : AttestationStatus()
    
    
    /**
     * Verification was attempted and failed.
     */
    data class Failed(
        val `reason`: kotlin.String) : AttestationStatus() {
        companion object
    }
    
    /**
     * Was verified but TTL has elapsed; re-verification pending.
     */
    object Expired : AttestationStatus()
    
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeAttestationStatus : FfiConverterRustBuffer<AttestationStatus>{
    override fun read(buf: ByteBuffer): AttestationStatus {
        return when(buf.getInt()) {
            1 -> AttestationStatus.Verified
            2 -> AttestationStatus.Unverified
            3 -> AttestationStatus.Failed(
                FfiConverterString.read(buf),
                )
            4 -> AttestationStatus.Expired
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: AttestationStatus) = when(value) {
        is AttestationStatus.Verified -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AttestationStatus.Unverified -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is AttestationStatus.Failed -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
        is AttestationStatus.Expired -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
    }

    override fun write(value: AttestationStatus, buf: ByteBuffer) {
        when(value) {
            is AttestationStatus.Verified -> {
                buf.putInt(1)
                Unit
            }
            is AttestationStatus.Unverified -> {
                buf.putInt(2)
                Unit
            }
            is AttestationStatus.Failed -> {
                buf.putInt(3)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is AttestationStatus.Expired -> {
                buf.putInt(4)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





