    }
}







/**
 * Error taxonomy for LLM operations -- crosses UniFFI boundary as exception type.
 * Per D-10: 5 variants mapping HTTP/network conditions to human-readable messages.
 */
sealed class LlmException: kotlin.Exception() {
    
    class NetworkException(
        
        val `reason`: kotlin.String
        ) : LlmException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class AuthException(
        
        val `reason`: kotlin.String
        ) : LlmException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class ModelNotFound(
        
        val `modelId`: kotlin.String
        ) : LlmException() {
        override val message
            get() = "modelId=${ `modelId` }"
    }
    
    class RateLimited(
        
        val `reason`: kotlin.String, 
        
        /**
         * Seconds from Retry-After header, if the server provided one.
         */
        val `retryAfterSecs`: kotlin.ULong?
        ) : LlmException() {
        override val message
            get() = "reason=${ `reason` }, retryAfterSecs=${ `retryAfterSecs` }"
    }
    
    class ApiException(
        
        val `statusCode`: kotlin.UShort, 
        
        val `reason`: kotlin.String
        ) : LlmException() {
        override val message
            get() = "statusCode=${ `statusCode` }, reason=${ `reason` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<LlmException> {
        override fun lift(error_buf: RustBuffer.ByValue): LlmException = FfiConverterTypeLlmError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeLlmError : FfiConverterRustBuffer<LlmException> {
    override fun read(buf: ByteBuffer): LlmException {
        

        return when(buf.getInt()) {
            1 -> LlmException.NetworkException(
                FfiConverterString.read(buf),
                )
            2 -> LlmException.AuthException(
                FfiConverterString.read(buf),
                )
            3 -> LlmException.ModelNotFound(
                FfiConverterString.read(buf),
                )
            4 -> LlmException.RateLimited(
                FfiConverterString.read(buf),
                FfiConverterOptionalULong.read(buf),
                )
            5 -> LlmException.ApiException(
                FfiConverterUShort.read(buf),
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: LlmException): ULong {
        return when(value) {
            is LlmException.NetworkException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is LlmException.AuthException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is LlmException.ModelNotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`modelId`)
            )
            is LlmException.RateLimited -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
                + FfiConverterOptionalULong.allocationSize(value.`retryAfterSecs`)
            )
            is LlmException.ApiException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterUShort.allocationSize(value.`statusCode`)
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: LlmException, buf: ByteBuffer) {
        when(value) {
            is LlmException.NetworkException -> {
                buf.putInt(1)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is LlmException.AuthException -> {
                buf.putInt(2)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is LlmException.ModelNotFound -> {
                buf.putInt(3)
                FfiConverterString.write(value.`modelId`, buf)
                Unit
            }
            is LlmException.RateLimited -> {
                buf.putInt(4)
                FfiConverterString.write(value.`reason`, buf)
                FfiConverterOptionalULong.write(value.`retryAfterSecs`, buf)
                Unit
            }
            is LlmException.ApiException -> {
                buf.putInt(5)
                FfiConverterUShort.write(value.`statusCode`, buf)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



